# PowerShell error handling with Invoke-AzRestMethod
$sub = (Get-AzContext).Subscription.Id
$response = Invoke-AzRestMethod `
  -Method GET `
  -Path "/subscriptions/$sub/resourceGroups/nonexistent?api-version=2021-04-01"

switch ($response.StatusCode) {
    200 { $response.Content | ConvertFrom-Json }
    404 { Write-Warning 'Resource group not found' }
    403 { Write-Error 'Insufficient permissions (check RBAC assignment)' }
    429 {
        $retryAfter = $response.Headers.GetValues('Retry-After')[0]
        Write-Warning "Rate limited. Retrying after ${retryAfter}s"
        Start-Sleep -Seconds $retryAfter
    }
    default {
        $err = $response.Content | ConvertFrom-Json
        Write-Error "API error $($response.StatusCode): $($err.error.message)"
    }
}
